mapper.select:
SELECT * FROM ( SELECT m.member_id, s.student_name AS name, m.login_id, m.email, 'STUDENT' AS role_code, '학생' AS role_name, m.account_status, TO_CHAR(m.last_login_at, 'YY/MM/DD') AS last_login_at, TO_CHAR(m.created_at, 'YY/MM/DD') AS created_at, NVL(( SELECT LISTAGG(c.class_name, ', ') WITHIN GROUP (ORDER BY c.class_id) FROM student_class sc JOIN class c ON sc.class_id = c.class_id WHERE sc.student_id = s.student_id ), '-') AS class_info, CASE WHEN EXISTS ( SELECT 1 FROM student_parent sp WHERE sp.student_id = s.student_id AND sp.link_status = 1 ) THEN '연결' ELSE '미연결' END AS connection_status, NVL(( SELECT MAX(ll.user_agent) KEEP (DENSE_RANK LAST ORDER BY ll.created_at) FROM login_log ll WHERE ll.member_id = m.member_id AND ll.login_result = 'SUCCESS' ), '-') AS device_info, NVL(( SELECT MAX(ll.ip_address) KEEP (DENSE_RANK LAST ORDER BY ll.created_at) FROM login_log ll WHERE ll.member_id = m.member_id AND ll.login_result = 'SUCCESS' ), '-') AS access_location FROM member m JOIN student s ON m.member_id = s.student_id WHERE m.member_id = #{memberId}
UNION ALL
SELECT m.member_id, p.parent_name AS name, m.login_id, m.email, 'PARENT' AS role_code, '학부모' AS role_name, m.account_status, TO_CHAR(m.last_login_at, 'YY/MM/DD') AS last_login_at, TO_CHAR(m.created_at, 'YY/MM/DD') AS created_at, NVL(( SELECT LISTAGG(c.class_name, ', ') WITHIN GROUP (ORDER BY c.class_id) FROM student_parent sp JOIN student_class sc ON sp.student_id = sc.student_id JOIN class c ON sc.class_id = c.class_id WHERE sp.parent_id = p.parent_id AND sp.link_status = 1 ), '-') AS class_info, CASE WHEN EXISTS ( SELECT 1 FROM student_parent sp WHERE sp.parent_id = p.parent_id AND sp.link_status = 1 ) THEN '연결' ELSE '미연결' END AS connection_status, NVL(( SELECT MAX(ll.user_agent) KEEP (DENSE_RANK LAST ORDER BY ll.created_at) FROM login_log ll WHERE ll.member_id = m.member_id AND ll.login_result = 'SUCCESS' ), '-') AS device_info, NVL(( SELECT MAX(ll.ip_address) KEEP (DENSE_RANK LAST ORDER BY ll.created_at) FROM login_log ll WHERE ll.member_id = m.member_id AND ll.login_result = 'SUCCESS' ), '-') AS access_location FROM member m JOIN parent p ON m.member_id = p.parent_id WHERE m.member_id = #{memberId} )
